sys_hub_input_scripts.script:
{"servicenowattachmentsinuse":{"scriptActive":true,"script":"/*
**Access Flow/Action data using the fd_data object. Script must return a value.
**example: var shortDesc = fd_data.trigger.current.short_description;
**return shortDesc;
*/
var AttachmentsInUse = new x_153465_discovert.taskerDocumentScripts().getAttachmentSystemSettings();
gs.debug('Run Template - Copy Attachment Folders - ServiceNow Attachments Settings - AttachmentsInUse.sNOWAttachmentsOn: ' + AttachmentsInUse.sNOWAttachmentsOn);
return AttachmentsInUse.sNOWAttachmentsOn;"}}

